"""Module for some node classes. More nodes in scoped_nodes.py"""

from __future__ import annotations

import abc
import itertools
import sys
import typing
import warnings
from collections.abc import Generator, Iterator
from functools import lru_cache
from typing import TYPE_CHECKING, Any, Callable, ClassVar, Optional, TypeVar, Union

from astroid import decorators, mixins, util
from astroid.bases import Instance, _infer_stmts
from astroid.const import Context
from astroid.context import InferenceContext
from astroid.exceptions import (
    AstroidIndexError,
    AstroidTypeError,
    InferenceError,
    NoDefault,
    ParentMissingError,
)
from astroid.manager import AstroidManager
from astroid.nodes.const import OP_PRECEDENCE
from astroid.nodes.node_ng import NodeNG

if sys.version_info >= (3, 8):
    from typing import Literal
else:
    from typing_extensions import Literal

if TYPE_CHECKING:
    from astroid import nodes
    from astroid.nodes import LocalsDictNodeNG

if sys.version_info >= (3, 8):
    from functools import cached_property
else:
    from astroid.decorators import cachedproperty as cached_property


def _is_const(value):
    return isinstance(value, tuple(CONST_CLS))


_NodesT = TypeVar("_NodesT", bound=NodeNG)

AssignedStmtsPossibleNode = Union["List", "Tuple", "AssignName", "AssignAttr", None]
AssignedStmtsCall = Callable[
    [
        _NodesT,
        AssignedStmtsPossibleNode,
        Optional[InferenceContext],
        Optional[typing.List[int]],
    ],
    Any,
]


@decorators.raise_if_nothing_inferred
def unpack_infer(stmt, context=None):
    """Recursively generate nodes inferred by the given statement.

    If the inferred value is a list or a tuple, recurse on the elements.
    """
    if isinstance(stmt, (List, Tuple)):
        for elt in stmt.elts:
            if elt is util.Uninferable:
                yield elt
                continue
            yield from unpack_infer(elt, context)
        return dict(node=stmt, context=context)

    inferred = next(stmt.infer(context), util.Uninferable)
    if inferred is stmt:
        yield inferred
        return dict(node=stmt, context=context)

    for inferred in stmt.infer(context):
        if inferred is util.Uninferable:
            yield inferred
        else:
            yield from unpack_infer(inferred, context)

    return dict(node=stmt, context=context)


def are_exclusive(stmt1, stmt2, exceptions: list[str] | None = None) -> bool:
    """Return True if the two given statements are mutually exclusive.

    `exceptions` may be a list of exception names. If specified, discard If
    branches and check one of the statement is in an exception handler catching
    one of the given exceptions.
    """
    stmt1_parents = {}
    children = {}
    previous = stmt1
    for node in stmt1.node_ancestors():
        stmt1_parents[node] = 1
        children[node] = previous
        previous = node

    previous = stmt2
    for node in stmt2.node_ancestors():
        if node in stmt1_parents:
            if isinstance(node, If) and exceptions is None:
                return _are_exclusive_if(node, previous, children[node])
            elif isinstance(node, TryExcept):
                return _are_exclusive_try_except(node, previous, children[node], exceptions)
        previous = node
    return False


def _are_exclusive_if(node: If, previous: NodeNG, child: NodeNG) -> bool:
    return (
        node.locate_child(previous)[1] is not node.locate_child(child)[1]
    )


def _are_exclusive_try_except(
    node: TryExcept, previous: NodeNG, child: NodeNG, exceptions: list[str] | None
) -> bool:
    c2attr, c2node = node.locate_child(previous)
    c1attr, c1node = node.locate_child(child)
    if c1node is not c2node:
        first_in_body_caught_by_handlers = (
            c2attr == "handlers" and c1attr == "body" and previous.catch(exceptions)
        )
        second_in_body_caught_by_handlers = (
            c2attr == "body" and c1attr == "handlers" and child.catch(exceptions)
        )
        first_in_else_other_in_handlers = c2attr == "handlers" and c1attr == "orelse"
        second_in_else_other_in_handlers = c2attr == "orelse" and c1attr == "handlers"
        return any(
            (
                first_in_body_caught_by_handlers,
                second_in_body_caught_by_handlers,
                first_in_else_other_in_handlers,
                second_in_else_other_in_handlers,
            )
        )
    elif c2attr == "handlers" and c1attr == "handlers":
        return previous is not child
    return False


_SLICE_SENTINEL = object()


def _slice_value(index, context=None):
    """Get the value of the given slice index."""
    if isinstance(index, Const):
        if isinstance(index.value, (int, type(None))):
            return index.value
    elif index is None:
        return None
    else:
        try:
            inferred = next(index.infer(context=context))
        except (InferenceError, StopIteration):
            pass
        else:
            if isinstance(inferred, Const):
                if isinstance(inferred.value, (int, type(None))):
                    return inferred.value

    return _SLICE_SENTINEL


def _infer_slice(node, context=None):
    lower = _slice_value(node.lower, context)
    upper = _slice_value(node.upper, context)
    step = _slice_value(node.step, context)
    if all(elem is not _SLICE_SENTINEL for elem in (lower, upper, step)):
        return slice(lower, upper, step)

    raise AstroidTypeError(
        message="Could not infer slice used in subscript",
        node=node,
        index=node.parent,
        context=context,
    )


def _container_getitem(instance, elts, index, context=None):
    """Get a slice or an item, using the given *index*, for the given sequence."""
    try:
        if isinstance(index, Slice):
            index_slice = _infer_slice(index, context=context)
            new_cls = instance.__class__()
            new_cls.elts = elts[index_slice]
            new_cls.parent = instance.parent
            return new_cls
        if isinstance(index, Const):
            return elts[index.value]
    except IndexError as exc:
        raise AstroidIndexError(
            message="Index {index!s} out of range",
            node=instance,
            index=index,
            context=context,
        ) from exc
    except TypeError as exc:
        raise AstroidTypeError(
            message="Type error {error!r}", node=instance, index=index, context=context
        ) from exc

    raise AstroidTypeError(f"Could not use {index} as subscript index")


class Statement(NodeNG):
    """Statement node adding a few attributes"""

    is_statement = True
    """Whether this node indicates a statement."""

    def next_sibling(self) -> NodeNG | None:
        """The next sibling statement node."""
        stmts = self.parent.child_sequence(self)
        index = stmts.index(self)
        try:
            return stmts[index + 1]
        except IndexError:
            return None

    def previous_sibling(self) -> NodeNG | None:
        """The previous sibling statement."""
        stmts = self.parent.child_sequence(self)
        index = stmts.index(self)
        if index >= 1:
            return stmts[index - 1]
        return None


class BaseContainer(
    mixins.ParentAssignTypeMixin, NodeNG, Instance, metaclass=abc.ABCMeta
):
    """Base class for Set, FrozenSet, Tuple and List."""

    _astroid_fields = ("elts",)

    def __init__(
        self,
        lineno: int | None = None,
        col_offset: int | None = None,
        parent: NodeNG | None = None,
        *,
        end_lineno: int | None = None,
        end_col_offset: int | None = None,
    ) -> None:
        self.elts: list[NodeNG] = []
        """The elements in the node."""

        super().__init__(
            lineno=lineno,
            col_offset=col_offset,
            end_lineno=end_lineno,
            end_col_offset=end_col_offset,
            parent=parent,
        )
```

