    # If inferred is a final node, return it and stop.
    yield from _unpack_infer_stmt(stmt, context)
    return dict(node=stmt, context=context)


def _unpack_infer_iter(stmt, context):
    """Recursively yield nodes inferred by the given list or tuple."""
    for elt in stmt.elts:
        if elt is util.Uninferable:
            yield elt
            continue
        yield from unpack_infer(elt, context)


def _unpack_infer_stmt(stmt, context):
    """Recursively yield nodes inferred by the given statement."""
    inferred = next(stmt.infer(context), util.Uninferable)
    if inferred is stmt:
        yield inferred
        return

    for inferred in stmt.infer(context):
        if inferred is util.Uninferable:
            yield inferred
        else:
            yield from unpack_infer(inferred, context)


def are_exclusive(stmt1, stmt2, exceptions: list[str] | None = None) -> bool:
    """Return True if the two given statements are mutually exclusive.

    `exceptions` may be a list of exception names. If specified, discard If
    branches and check one of the statement is in an exception handler catching
    one of the given exceptions.

    Algorithm:
     1) Index stmt1's parents.
     2) Climb among stmt2's parents until we find a common parent.
     3) If the common parent is a If or TryExcept statement, look if nodes are
        in exclusive branches.
    """
    stmt1_parents = _index_stmt_parents(stmt1)
    common_parent = _find_common_parent(stmt1_parents, stmt2)
    if not common_parent:
        return False

    return _check_exclusive_branches(common_parent, stmt1, stmt2, exceptions)


def _index_stmt_parents(stmt):
    """Index parents of the given statement."""
    stmt1_parents = {}
    children = {}
    previous = stmt
    for node in stmt.node_ancestors():
        stmt1_parents[node] = 1
        children[node] = previous
        previous = node
    return stmt1_parents


def _find_common_parent(stmt1_parents, stmt2):
    """Find common parent between stmt2 and indexed parents."""
    previous = stmt2
    for node in stmt2.node_ancestors():
        if node in stmt1_parents:
            return node
        previous = node
    return None


def _check_exclusive_branches(common_parent, stmt1, stmt2, exceptions):
    """Check if the two statements are in exclusive branches."""
    if isinstance(common_parent, If) and exceptions is None:
        return _check_if_exclusive(common_parent, stmt1, stmt2)
    elif isinstance(common_parent, TryExcept):
        return _check_try_except_exclusive(common_parent, stmt1, stmt2, exceptions)
    return False


def _check_if_exclusive(if_node, stmt1, stmt2):
    """Check if the two statements are in exclusive if branches."""
    return (
        if_node.locate_child(stmt2)[1] != if_node.locate_child(stmt1)[1]
    )


def _check_try_except_exclusive(try_except_node, stmt1, stmt2, exceptions):
    """Check if the two statements are in exclusive try-except branches."""
    c2attr, c2node = try_except_node.locate_child(stmt2)
    c1attr, c1node = try_except_node.locate_child(stmt1)
    if c1node is not c2node:
        first_in_body_caught_by_handlers = (
            c2attr == "handlers" and c1attr == "body" and stmt2.catch(exceptions)
        )
        second_in_body_caught_by_handlers = (
            c2attr == "body" and c1attr == "handlers" and stmt1.catch(exceptions)
        )
        first_in_else_other_in_handlers = c2attr == "handlers" and c1attr == "orelse"
        second_in_else_other_in_handlers = c2attr == "orelse" and c1attr == "handlers"
        return any(
            (
                first_in_body_caught_by_handlers,
                second_in_body_caught_by_handlers,
                first_in_else_other_in_handlers,
                second_in_else_other_in_handlers,
            )
        )
    elif c2attr == "handlers" and c1attr == "handlers":
        return stmt2 is not stmt1
    return False


# getitem() helpers.

_SLICE_SENTINEL = object()


def _slice_value(index, context=None):
    """Get the value of the given slice index."""
    if isinstance(index, Const):
        if isinstance(index.value, (int, type(None))):
            return index.value
    elif index is None:
        return None
    else:
        # Try to infer what the index actually is.
        # Since we can't return all the possible values,
        # we'll stop at the first possible value.
        try:
            inferred = next(index.infer(context=context))
        except (InferenceError, StopIteration):
            pass
        else:
            if isinstance(inferred, Const):
                if isinstance(inferred.value, (int, type(None))):
                    return inferred.value

    # Use a sentinel, because None can be a valid
    # value that this function can return,
    # as it is the case for unspecified bounds.
    return _SLICE_SENTINEL


def _infer_slice(node, context=None):
    lower = _slice_value(node.lower, context)
    upper = _slice_value(node.upper, context)
    step = _slice_value(node.step, context)
    if all(elem is not _SLICE_SENTINEL for elem in (lower, upper, step)):
        return slice(lower, upper, step)

    raise AstroidTypeError(
        message="Could not infer slice used in subscript",
        node=node,
        index=node.parent,
        context=context,
    )


def _container_getitem(instance, elts, index, context=None):
    """Get a slice or an item, using the given *index*, for the given sequence."""
    try:
        if isinstance(index, Slice):
            index_slice = _infer_slice(index, context=context)
            new_cls = instance.__class__()
            new_cls.elts = elts[index_slice]
            new_cls.parent = instance.parent
            return new_cls
        if isinstance(index, Const):
            return elts[index.value]
    except IndexError as exc:
        raise AstroidIndexError(
            message="Index {index!s} out of range",
            node=instance,
            index=index,
            context=context,
        ) from exc
    except TypeError as exc:
        raise AstroidTypeError(
            message="Type error {error!r}", node=instance, index=index, context=context
        ) from exc

    raise AstroidTypeError(f"Could not use {index} as subscript index")


class Statement(NodeNG):
    """Statement node adding a few attributes"""

    is_statement = True
    """Whether this node indicates a statement."""

    def next_sibling(self):
        """The next sibling statement node.

        :returns: The next sibling statement node.
        :rtype: NodeNG or None
        """
        stmts = self.parent.child_sequence(self)
        index = stmts.index(self)

